using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    [McpServerTool, Description("Fetch data from an external API endpoint and return the JSON response.")]
    public async Task<string> FetchApi(
        [Description("Full URL of the API endpoint to call")] string url,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Calling external API: {Url}", url);

        var response = await httpClient.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync(cancellationToken);

        // Pretty-print to make the output easier for the LLM to read
        using var doc = JsonDocument.Parse(json);
        return JsonSerializer.Serialize(doc, new JsonSerializerOptions { WriteIndented = true });
    }
}

using System.ComponentModel;
using Microsoft.Extensions.AI;
using ModelContextProtocol.Server;

[McpServerPromptType]
public static class SummarizationPrompts
{
    [McpServerPrompt, Description("Summarize the provided content into a concise paragraph.")]
    public static ChatMessage Summarize(
        [Description("The text content to summarize")] string content) =>
        new(ChatRole.User, $"Summarize the following content into a concise paragraph:\n\n{content}");

    [McpServerPrompt, Description("Summarize content with a specific focus area.")]
    public static ChatMessage SummarizeWithFocus(
        [Description("The text content to summarize")] string content,
        [Description("The aspect to focus on (e.g., 'key takeaways', 'action items', 'technical details')")] string focus) =>
        new(ChatRole.User, $"Summarize the following content, focusing on {focus}:\n\n{content}");
}

